example.code:
locals { # Naming convention name_prefix = "${var.project}-${var.environment}"
# Common tags applied everywhere common_tags = { Project = var.project Environment = var.environment ManagedBy = "terraform" CostCenter = var.cost_center }
# Computed CIDR blocks public_cidrs = [for i in range(3) : cidrsubnet(var.vpc_cidr, 4, i)] private_cidrs = [for i in range(3) : cidrsubnet(var.vpc_cidr, 4, i + 3)] database_cidrs = [for i in range(3) : cidrsubnet(var.vpc_cidr, 4, i + 6)]
# Environment-specific configuration is_production = var.environment == "prod"
instance_class = local.is_production ? "db.r6g.xlarge" : "db.t4g.medium" multi_az = local.is_production ? true : false
# Merge user-provided values with defaults final_config = merge(local.default_config, var.custom_config) }

variable "buckets" {
  description = "Map of bucket configurations"
  type = map(object({
    versioning = optional(bool, true)
    lifecycle_rules = optional(list(object({
      id      = string
      enabled = bool
      expiration_days = optional(number)
    })), [])
  }))
}

resource "aws_s3_bucket" "buckets" {
  for_each = var.buckets

  bucket = "${var.name_prefix}-${each.key}"

  tags = merge(var.tags, {
    Name = "${var.name_prefix}-${each.key}"
  })
}

resource "aws_s3_bucket_versioning" "buckets" {
  for_each = var.buckets

  bucket = aws_s3_bucket.buckets[each.key].id
  versioning_configuration {
    status = each.value.versioning ? "Enabled" : "Disabled"
  }
}

variable "ingress_rules" {
  description = "List of ingress rules"
  type = list(object({
    port        = number
    protocol    = optional(string, "tcp")
    cidr_blocks = list(string)
    description = optional(string, "")
  }))
  default = []
}

resource "aws_security_group" "app" {
  name_prefix = "${local.name_prefix}-app-"
  vpc_id      = var.vpc_id

  dynamic "ingress" {
    for_each = var.ingress_rules
    content {
      from_port   = ingress.value.port
      to_port     = ingress.value.port
      protocol    = ingress.value.protocol
      cidr_blocks = ingress.value.cidr_blocks
      description = ingress.value.description
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = local.common_tags

  lifecycle {
    create_before_destroy = true
  }
}

# terragrunt.hcl (root)

locals {
  # Parse the file path to extract environment and region
  path_parts = split("/", path_relative_to_include())

  environment = try(local.path_parts[0], "dev")
  region      = try(local.path_parts[1], "us-east-1")

  # Load environment-specific variables
  env_vars = read_terragrunt_config(find_in_parent_folders("env.hcl", "env.hcl"))

  # Common tags for all resources
  common_tags = {
    Environment = local.environment
    ManagedBy   = "terragrunt"
    Region      = local.region
  }
}

# Generate provider configuration
generate "provider" {
  path      = "provider.tf"
  if_exists = "overwrite_terragrunt"
  contents  = <<EOF
provider "aws" {
  region = "${local.region}"

  default_tags {
    tags = ${jsonencode(local.common_tags)}
  }
}
EOF
}

# Remote state configuration
remote_state {
  backend = "s3"
  generate = {
    path      = "backend.tf"
    if_exists = "overwrite_terragrunt"
  }
  config = {
    bucket         = "company-terraform-state-${get_aws_account_id()}"
    key            = "${path_relative_to_include()}/terraform.tfstate"
    region         = "us-east-1"
    encrypt        = true
    dynamodb_table = "terraform-locks"
  }
}

# Common inputs for all modules
inputs = {
  environment = local.environment
  region      = local.region
  tags        = local.common_tags
}

# environments/prod/us-east-1/vpc/terragrunt.hcl

include "root" {
  path = find_in_parent_folders()
}

terraform {
  source = "${get_repo_root()}/modules/vpc"
}

inputs = {
  name_prefix        = "myapp-prod"
  vpc_cidr           = "10.0.0.0/16"
  availability_zones = ["us-east-1a", "us-east-1b", "us-east-1c"]

  enable_nat_gateway = true
  single_nat_gateway = false  # Production: NAT per AZ
}
